#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=1e4+5;
int Tmax,N,d[MAXN];
bool f(int x){
	priority_queue<int,vector<int> ,greater<int> > q;
	int t=x;
	for(int i=1;i<=t;++i)q.push(d[i]);
	while(++t<=N){
		int tmp=q.top();
		if(tmp+d[t]>Tmax)return false;
		else q.pop(),q.push(tmp+d[t]);
	}return true;
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d",&N,&Tmax);
	for(int i=1;i<=N;++i)scanf("%d",d+i);
	int l=0,r=1e4;
    while(l+1<r){
        int mid=(l+r)>>1;
        if(f(mid))r=mid;
        else l=mid;
    }printf("%d",r);
	return false;
}
